This sample shows how to call CreateAgentAsync.

Uri endpoint = new Uri("<endpoint>");
TokenCredential credential = new DefaultAzureCredential();
Agents client = new AIProjectClient(endpoint, credential).GetAgentsClient(apiVersion: "virtual-public-preview");

AgentDefinition definition = new HostedAgentDefinition("<cpu>", "<memory>");
Response<AgentObject> response = await client.CreateAgentAsync("<name>", definition);

This sample shows how to call CreateAgentAsync with all parameters.

Uri endpoint = new Uri("<endpoint>");
TokenCredential credential = new DefaultAzureCredential();
Agents client = new AIProjectClient(endpoint, credential).GetAgentsClient(apiVersion: "virtual-public-preview");

AgentDefinition definition = new HostedAgentDefinition("<cpu>", "<memory>")
{
    Tools = {new BingGroundingTool(new BingGroundingSearchToolParameters(new BingGroundingSearchConfiguration[]
    {
        new BingGroundingSearchConfiguration("<project_connection_id>")
        {
            Market = "<market>",
            SetLang = "<set_lang>",
            Count = 1234L,
            Freshness = "<freshness>",
        }
    }))},
    ContainerProtocolVersions = { new ProtocolVersionRecord(AgentProtocol.ActivityProtocol, "<version>") },
    EnvironmentVariables =
    {
        ["key"] = "<environment_variables>"
    },
    Image = "<image>",
    ContainerConfiguration = new ContainerConfiguration("<image>"),
    ProtocolVersions = { default },
    CodeConfiguration = new CodeConfiguration("<runtime>", new string[] { "<entry_point>" }),
    RaiConfig = new RaiConfig("<rai_policy_name>"),
};
AgentBlueprintReference blueprintReference = new ManagedAgentIdentityBlueprintReference("<blueprint_id>");
AgentEndpoint agentEndpoint = new AgentEndpoint
{
    VersionSelector = new VersionSelector(new VersionSelectionRule[]
    {
        new FixedRatioVersionSelectionRule("<agent_version>", 1234)
    }),
    Protocols = { AgentEndpointProtocol.Activity },
    AuthorizationSchemes = { new EntraAuthorizationScheme(new EntraIsolationKeySource()) },
};
AgentCard agentCard = new AgentCard("<version>", new AgentCardSkill[]
{
    new AgentCardSkill("<id>", "<name>")
    {
        Description = "<description>",
        Tags = {"<tags>"},
        Examples = {"<examples>"},
    }
})
{
    Description = "<description>",
};
Response<AgentObject> response = await client.CreateAgentAsync("<name>", definition, metadata: new Dictionary<string, string>
{
    ["key"] = "<metadata>"
}, description: "<description>", blueprintReference: blueprintReference, agentEndpoint: agentEndpoint, agentCard: agentCard, foundryFeatures: AgentDefinitionOptInKeys.HostedAgentsV1Preview);

