This sample shows how to call CreateAgentAsync and parse the result.

Uri endpoint = new Uri("<endpoint>");
TokenCredential credential = new DefaultAzureCredential();
Agents client = new AIProjectClient(endpoint, credential).GetAgentsClient(apiVersion: "virtual-public-preview");

using RequestContent content = RequestContent.Create(new
{
    name = "<name>",
    definition = new
    {
        kind = "hosted",
        cpu = "<cpu>",
        memory = "<memory>",
    },
});
Response response = await client.CreateAgentAsync(content);

JsonElement result = JsonDocument.Parse(response.ContentStream).RootElement;
Console.WriteLine(result.GetProperty("object").ToString());
Console.WriteLine(result.GetProperty("id").ToString());
Console.WriteLine(result.GetProperty("name").ToString());
Console.WriteLine(result.GetProperty("versions").GetProperty("latest").GetProperty("metadata").GetProperty("<key>").ToString());
Console.WriteLine(result.GetProperty("versions").GetProperty("latest").GetProperty("object").ToString());
Console.WriteLine(result.GetProperty("versions").GetProperty("latest").GetProperty("id").ToString());
Console.WriteLine(result.GetProperty("versions").GetProperty("latest").GetProperty("name").ToString());
Console.WriteLine(result.GetProperty("versions").GetProperty("latest").GetProperty("version").ToString());
Console.WriteLine(result.GetProperty("versions").GetProperty("latest").GetProperty("created_at").ToString());
Console.WriteLine(result.GetProperty("versions").GetProperty("latest").GetProperty("definition").GetProperty("kind").ToString());

This sample shows how to call CreateAgentAsync with all parameters and request content and parse the result.

Uri endpoint = new Uri("<endpoint>");
TokenCredential credential = new DefaultAzureCredential();
Agents client = new AIProjectClient(endpoint, credential).GetAgentsClient(apiVersion: "virtual-public-preview");

using RequestContent content = RequestContent.Create(new
{
    name = "<name>",
    metadata = new
    {
        key = "<metadata>",
    },
    description = "<description>",
    definition = new
    {
        kind = "hosted",
        tools = new object[]
        {
            new
            {
                type = "bing_grounding",
                bing_grounding = new
                {
                    search_configurations = new object[]
                    {
                        new
                        {
                            project_connection_id = "<project_connection_id>",
                            market = "<market>",
                            set_lang = "<set_lang>",
                            count = 1234L,
                            freshness = "<freshness>",
                        }
                    },
                },
            }
        },
        container_protocol_versions = new object[]
        {
            new
            {
                protocol = "activity_protocol",
                version = "<version>",
            }
        },
        cpu = "<cpu>",
        memory = "<memory>",
        environment_variables = new
        {
            key = "<environment_variables>",
        },
        image = "<image>",
        container_configuration = new
        {
            image = "<image>",
        },
        protocol_versions = new object[]
        {
            null
        },
        code_configuration = new
        {
            runtime = "<runtime>",
            entry_point = new object[]
            {
                "<entry_point>"
            },
        },
        rai_config = new
        {
            rai_policy_name = "<rai_policy_name>",
        },
    },
    blueprint_reference = new
    {
        type = "ManagedAgentIdentityBlueprint",
        blueprint_id = "<blueprint_id>",
    },
    agent_endpoint = new
    {
        version_selector = new
        {
            version_selection_rules = new object[]
            {
                new
                {
                    type = "FixedRatio",
                    traffic_percentage = 1234,
                    agent_version = "<agent_version>",
                }
            },
        },
        protocols = new object[]
        {
            "activity"
        },
        authorization_schemes = new object[]
        {
            new
            {
                type = "Entra",
                isolation_key_source = new
                {
                    kind = "Entra",
                },
            }
        },
    },
    agent_card = new
    {
        version = "<version>",
        description = "<description>",
        skills = new object[]
        {
            new
            {
                id = "<id>",
                name = "<name>",
                description = "<description>",
                tags = new object[]
                {
                    "<tags>"
                },
                examples = new object[]
                {
                    "<examples>"
                },
            }
        },
    },
});
Response response = await client.CreateAgentAsync(content, foundryFeatures: "HostedAgents=V1Preview");

JsonElement result = JsonDocument.Parse(response.ContentStream).RootElement;
