    Console.WriteLine(result.GetProperty("version_indicator").GetProperty("type").ToString());
    Console.WriteLine(result.GetProperty("status").ToString());
    Console.WriteLine(result.GetProperty("created_at").ToString());
    Console.WriteLine(result.GetProperty("last_accessed_at").ToString());
    Console.WriteLine(result.GetProperty("expires_at").ToString());
}

